import{_ as a,o as e,c as r,ag as d}from"./chunks/framework.CQYuu_FX.js";const u=JSON.parse('{"title":"セキュリティ","description":"","frontmatter":{"title":"セキュリティ"},"headers":[],"relativePath":"tenant/18-security.md","filePath":"tenant/18-security.md"}'),i={name:"tenant/18-security.md"};function l(o,t,h,n,s,c){return e(),r("div",null,[...t[0]||(t[0]=[d('<h1 id="_18-セキュリティ" tabindex="-1">18. セキュリティ <a class="header-anchor" href="#_18-セキュリティ" aria-label="Permalink to &quot;18. セキュリティ&quot;">​</a></h1><p>POSLAを安全に利用するため、アカウント、パスワード、PIN、端末、権限管理の基本ルールを守ってください。</p><h2 id="基本ルール" tabindex="-1">基本ルール <a class="header-anchor" href="#基本ルール" aria-label="Permalink to &quot;基本ルール&quot;">​</a></h2><ul><li>1人1アカウントで利用してください。</li><li>共有アカウントは使用しないでください。</li><li>退職者のアカウントは速やかに無効化してください。</li><li>パスワードは他サービスと使い回さないでください。</li><li>レジやKDSなどの店舗備品は端末専用アカウントで運用してください。</li><li>現金や返金に関わる操作では、担当スタッフのPINを使用してください。</li></ul><h2 id="権限管理" tabindex="-1">権限管理 <a class="header-anchor" href="#権限管理" aria-label="Permalink to &quot;権限管理&quot;">​</a></h2><table tabindex="0"><thead><tr><th>ロール</th><th>管理ポイント</th></tr></thead><tbody><tr><td>オーナー</td><td>全店舗に影響するため、必要な人だけに付与してください。</td></tr><tr><td>マネージャー</td><td>担当店舗の運用責任者に付与してください。</td></tr><tr><td>スタッフ</td><td>日常業務に必要な範囲で付与してください。</td></tr><tr><td>端末専用</td><td>店舗備品端末のみに使用してください。</td></tr></tbody></table><h2 id="監査ログ" tabindex="-1">監査ログ <a class="header-anchor" href="#監査ログ" aria-label="Permalink to &quot;監査ログ&quot;">​</a></h2><p>POSLAでは、重要な操作が記録されます。返金、レジ操作、ユーザー変更、設定変更などに不審な点がある場合は、監査ログを確認してください。</p><h2 id="端末管理" tabindex="-1">端末管理 <a class="header-anchor" href="#端末管理" aria-label="Permalink to &quot;端末管理&quot;">​</a></h2><p>共有端末では、ブラウザの保存パスワードや個人アカウントの利用に注意してください。端末の紛失や盗難があった場合は、すぐにパスワード変更とアカウント無効化を行ってください。</p><h2 id="困ったとき" tabindex="-1">困ったとき <a class="header-anchor" href="#困ったとき" aria-label="Permalink to &quot;困ったとき&quot;">​</a></h2><table tabindex="0"><thead><tr><th>症状</th><th>対処</th></tr></thead><tbody><tr><td>不審なログインがある</td><td>パスワード変更、該当アカウントの無効化、POSLAサポートへの連絡を行ってください。</td></tr><tr><td>PINが漏れた可能性がある</td><td>すぐにPINを変更してください。</td></tr><tr><td>退職者がログインできる</td><td>アカウントを無効化してください。</td></tr><tr><td>権限が強すぎる</td><td>ロールを見直してください。</td></tr></tbody></table>',12)])])}const b=a(i,[["render",l]]);export{u as __pageData,b as default};
